final:
module RefModule(
    input clk,
    input reset,
    input in,
    output reg [3:0] out);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
        if (reset)
            out <= 4'b0000;
        else
            out <= {out[2:0], in};
    end
endmodule
